import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import Navbar from '../components/shared/Navbar';
import { bookingAPI, paymentAPI } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import { format } from 'date-fns';
import toast from 'react-hot-toast';

const STATUS_COLORS = { pending: 'warning', accepted: 'accent', in_progress: 'accent', completed: 'success', rejected: 'danger', cancelled: 'danger' };
const STATUS_ICONS = { pending: '⏳', accepted: '✅', in_progress: '🔧', completed: '🎉', rejected: '❌', cancelled: '🚫' };

export default function BookingDetailPage() {
  const { id } = useParams();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [booking, setBooking] = useState(null);
  const [loading, setLoading] = useState(true);
  const [paymentLoading, setPaymentLoading] = useState(false);

  useEffect(() => {
    bookingAPI.getById(id)
      .then(r => setBooking(r.data.data))
      .catch(() => toast.error('Booking not found'))
      .finally(() => setLoading(false));
  }, [id]);

  const initiatePayment = async () => {
    setPaymentLoading(true);
    try {
      const { data } = await paymentAPI.createOrder({ bookingId: id });

      // Load Razorpay script
      const script = document.createElement('script');
      script.src = 'https://checkout.razorpay.com/v1/checkout.js';
      document.body.appendChild(script);
      script.onload = () => {
        const options = {
          key: data.key || 'rzp_test_key',
          amount: data.order.amount,
          currency: 'INR',
          name: 'SkillBridge',
          description: `Payment for ${booking.skillRequired}`,
          order_id: data.order.id,
          handler: async (response) => {
            try {
              await paymentAPI.verify({
                razorpay_order_id: response.razorpay_order_id,
                razorpay_payment_id: response.razorpay_payment_id,
                razorpay_signature: response.razorpay_signature,
                paymentId: data.payment,
              });
              toast.success('Payment successful! 🎉');
              bookingAPI.getById(id).then(r => setBooking(r.data.data));
            } catch { toast.error('Payment verification failed'); }
          },
          prefill: { name: user.name, email: user.email, contact: user.phone },
          theme: { color: '#4f7fff' },
        };
        new window.Razorpay(options).open();
      };
    } catch (err) {
      toast.error(err.response?.data?.message || 'Payment failed to initialize');
    } finally {
      setPaymentLoading(false);
    }
  };

  const cancelBooking = async () => {
    if (!window.confirm('Cancel this booking?')) return;
    try {
      await bookingAPI.updateStatus(id, { status: 'cancelled', note: 'Cancelled by user' });
      toast.success('Booking cancelled');
      bookingAPI.getById(id).then(r => setBooking(r.data.data));
    } catch { toast.error('Failed to cancel'); }
  };

  if (loading) return <div><Navbar /><div className="page-container" style={{ paddingTop: 40 }}><div className="spinner" /></div></div>;
  if (!booking) return null;

  const provUser = booking.provider?.user || {};
  const isUser = booking.user?._id === user.id || booking.user === user.id;

  return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar />
      <div className="page-container" style={{ paddingTop: 32, paddingBottom: 48, maxWidth: 760 }}>
        <button className="btn btn-ghost btn-sm" style={{ marginBottom: 20 }} onClick={() => navigate(-1)}>← Back</button>

        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24, flexWrap: 'wrap', gap: 12 }}>
          <h1 style={{ fontSize: 24, fontWeight: 800 }}>Booking Details</h1>
          <span className={`badge badge-${STATUS_COLORS[booking.status]}`} style={{ fontSize: 13, padding: '6px 14px' }}>
            {STATUS_ICONS[booking.status]} {booking.status.replace('_', ' ')}
          </span>
        </div>

        {/* Provider Card */}
        <div className="card" style={{ marginBottom: 16 }}>
          <div style={{ display: 'flex', gap: 14, alignItems: 'center', marginBottom: 16 }}>
            <div style={{ width: 48, height: 48, borderRadius: '50%', background: 'var(--accent-dim)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--accent)', fontWeight: 700, fontSize: 16 }}>
              {provUser.name?.split(' ').map(n => n[0]).join('').slice(0, 2)}
            </div>
            <div>
              <div style={{ fontWeight: 700 }}>{provUser.name}</div>
              <div style={{ fontSize: 13, color: 'var(--text-secondary)' }}>{booking.serviceCategory}</div>
            </div>
            <button className="btn btn-secondary btn-sm" style={{ marginLeft: 'auto' }}
              onClick={() => navigate(`/chat/${provUser._id}`)}>💬 Chat</button>
          </div>
        </div>

        {/* Service Details */}
        <div className="card" style={{ marginBottom: 16 }}>
          <h3 style={{ fontWeight: 700, marginBottom: 14, fontSize: 15 }}>Service Details</h3>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2,1fr)', gap: 12 }}>
            {[
              { label: 'Service', value: booking.skillRequired },
              { label: 'Category', value: booking.serviceCategory },
              { label: 'Date', value: format(new Date(booking.scheduledDate), 'EEE, d MMM yyyy') },
              { label: 'Time', value: booking.scheduledTime },
              { label: 'Address', value: booking.address?.text },
              { label: 'Booking ID', value: `#${booking._id.slice(-8).toUpperCase()}` },
            ].map(item => (
              <div key={item.label} style={{ background: 'var(--bg-secondary)', borderRadius: 'var(--radius)', padding: '10px 14px' }}>
                <div style={{ fontSize: 11, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: 1 }}>{item.label}</div>
                <div style={{ fontSize: 14, color: 'var(--text-primary)', marginTop: 3, fontWeight: 500 }}>{item.value}</div>
              </div>
            ))}
          </div>
          {booking.description && (
            <div style={{ marginTop: 12, background: 'var(--bg-secondary)', borderRadius: 'var(--radius)', padding: '10px 14px' }}>
              <div style={{ fontSize: 11, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: 1, marginBottom: 4 }}>Description</div>
              <p style={{ fontSize: 14, color: 'var(--text-secondary)', lineHeight: 1.6 }}>{booking.description}</p>
            </div>
          )}
        </div>

        {/* Payment Card */}
        <div className="card" style={{ marginBottom: 16 }}>
          <h3 style={{ fontWeight: 700, marginBottom: 14, fontSize: 15 }}>Payment</h3>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}>
            <div>
              {booking.finalPrice ? (
                <div style={{ fontSize: 24, fontWeight: 800, fontFamily: 'var(--font-display)', color: 'var(--success)' }}>₹{booking.finalPrice}</div>
              ) : (
                <div>
                  <div style={{ fontSize: 22, fontWeight: 800, fontFamily: 'var(--font-display)', color: 'var(--success)' }}>₹{booking.estimatedPrice?.min} – ₹{booking.estimatedPrice?.max}</div>
                  <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>Estimated range</div>
                </div>
              )}
            </div>
            <span className={`badge badge-${booking.paymentStatus === 'paid' ? 'success' : 'warning'}`} style={{ fontSize: 12 }}>
              {booking.paymentStatus === 'paid' ? '✅ Paid' : '⏳ Unpaid'}
            </span>
          </div>

          {isUser && booking.status === 'accepted' && booking.paymentStatus !== 'paid' && (
            <button className="btn btn-primary" style={{ width: '100%' }}
              onClick={initiatePayment} disabled={paymentLoading}>
              {paymentLoading ? 'Initializing...' : '💳 Pay with Razorpay'}
            </button>
          )}
        </div>

        {/* Status Timeline */}
        <div className="card" style={{ marginBottom: 16 }}>
          <h3 style={{ fontWeight: 700, marginBottom: 16, fontSize: 15 }}>Status Timeline</h3>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            {booking.statusHistory?.map((s, i) => (
              <div key={i} style={{ display: 'flex', gap: 12, alignItems: 'flex-start' }}>
                <div style={{ width: 28, height: 28, borderRadius: '50%', background: 'var(--bg-elevated)', border: '2px solid var(--border-light)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 12, flexShrink: 0 }}>
                  {STATUS_ICONS[s.status]}
                </div>
                <div>
                  <div style={{ fontWeight: 600, fontSize: 14, textTransform: 'capitalize' }}>{s.status.replace('_', ' ')}</div>
                  <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>{format(new Date(s.timestamp), 'dd MMM yyyy, h:mm a')}</div>
                  {s.note && <div style={{ fontSize: 12, color: 'var(--text-secondary)', marginTop: 2 }}>{s.note}</div>}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Actions */}
        {isUser && ['pending', 'accepted'].includes(booking.status) && (
          <button className="btn btn-danger btn-sm" onClick={cancelBooking}>🚫 Cancel Booking</button>
        )}
      </div>
    </div>
  );
}
